       `helpdesk_tickets`.`is_incoming` AS t0_r9, 
       `helpdesk_tickets`.`reaction_time` AS t0_r10, 
       `helpdesk_tickets`.`first_response_time` AS t0_r11, 
       `helpdesk_tickets`.`resolve_time` AS t0_r12, 
       `helpdesk_tickets`.`last_agent_response_at` AS t0_r13, 
