       `issues`.`fixed_version_id` AS t1_r10, 
       `issues`.`author_id` AS t1_r11, 
       `issues`.`lock_version` AS t1_r12, 
       `issues`.`created_on` AS t1_r13, 
       `issues`.`updated_on` AS t1_r14, 
       `issues`.`start_date` AS t1_r15, 
       `issues`.`done_ratio` AS t1_r16, 
