       `projects`.`enable_new_ticket_message` AS t2_r16, 
       `projects`.`default_issue_query_id` AS t2_r17 
FROM `helpdesk_tickets` 
LEFT OUTER JOIN `issues` ON `issues`.`id` = `helpdesk_tickets`.`issue_id` 
LEFT OUTER JOIN `projects` ON `projects`.`id` = `issues`.`project_id` 
WHERE `projects`.`id` = 161;

-- Analysis:
-- - Returns 17,156 rows
-- - 61 columns per row (19 + 24 + 18)
-- - Total data points: ~1,046,516
-- - Forces full table scan with eager loading
-- - Query times out after 120 seconds

-- ============================================
-- FAST QUERY (Optimized)
-- Generated by: HelpdeskTicket.joins(:issue).where(:issues => { project_id: 161 }).count
-- Performance: <100ms
-- ============================================

SELECT COUNT(*) 
FROM `helpdesk_tickets` 
INNER JOIN `issues` ON `issues`.`id` = `helpdesk_tickets`.`issue_id` 
WHERE `issues`.`project_id` = 161;

-- Analysis:
-- - Returns 1 row with single integer
-- - Uses index issues_project_id on WHERE clause
-- - Uses index index_helpdesk_tickets_on_issue_id_and_contact_id on JOIN
-- - Query completes in milliseconds

-- ============================================
-- FAST QUERY (Customer Count)
-- Generated by: HelpdeskTicket.joins(:issue)...distinct.count(:contact_id)
-- Performance: <100ms
-- ============================================

SELECT COUNT(DISTINCT `helpdesk_tickets`.`contact_id`) 
FROM `helpdesk_tickets` 
INNER JOIN `issues` ON `issues`.`id` = `helpdesk_tickets`.`issue_id` 
WHERE `issues`.`project_id` = 161 
AND `helpdesk_tickets`.`contact_id` IS NOT NULL;

-- Analysis:
-- - Returns 1 row with distinct count
-- - Uses same indexes as ticket count
-- - WHERE NOT NULL filters out tickets without contacts
-- - Query completes in milliseconds

-- ============================================
-- EXPLAIN PLAN Comparison
-- ============================================

-- Slow Query EXPLAIN:
-- EXPLAIN SELECT ... FROM helpdesk_tickets LEFT OUTER JOIN issues ... LEFT OUTER JOIN projects ... WHERE projects.id = 161;
-- Expected: Full table scan, no index usage on WHERE, temporary table for result

-- Fast Query EXPLAIN:
-- EXPLAIN SELECT COUNT(*) FROM helpdesk_tickets INNER JOIN issues ... WHERE issues.project_id = 161;
-- Expected: Using index issues_project_id, ref lookup, no temporary table

-- ============================================
-- Available Indexes (Verified)
-- ============================================

-- Issues table:
--   issues_project_id: (project_id)

-- HelpdeskTickets table:
--   index_helpdesk_tickets_on_issue_id_and_contact_id: (issue_id, contact_id)

-- These indexes support the fast queries but are not utilized by the includes() + count() pattern
